<template><div class="workspace-page"><section class="page-intro"><div><p>机构标准化数据</p><h2>体检报告</h2><span>机构提交后自动归档并只读开放；原始 OCR 文件不会向用户展示。</span></div></section><el-card shadow="never"><el-table :data="items" v-loading="loading" empty-text="暂无体检报告"><el-table-column prop="display_id" label="报告编号"/><el-table-column label="机构"><template #default="s">{{s.row.institution?.name}} · {{s.row.institution?.branch_name}}</template></el-table-column><el-table-column prop="exam_date" label="体检日期"/><el-table-column prop="indicator_count" label="指标数"/><el-table-column width="100"><template #default="s"><el-button link type="primary" @click="$router.push({name:'report-detail',params:{id:s.row.id}})">查看</el-button></template></el-table-column></el-table></el-card></div></template><script setup>import{onMounted,ref}from"vue";import{fetchExamReports}from"../api/examReports";const items=ref([]),loading=ref(false);onMounted(async()=>{loading.value=true;try{items.value=(await fetchExamReports()).data.items||[]}finally{loading.value=false}});</script>
